import json
from pathlib import Path
from decimal import Decimal, ROUND_HALF_UP

def validate_invoice(invoice):
    def round_money(value):
        return float(Decimal(str(value)).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP))

    computed_subtotal = round_money(sum(item['quantity'] * item['unit_price'] for item in invoice['line_items']))
    computed_discount = round_money(computed_subtotal * invoice['discount_pct'] / 100)
    computed_tax = round_money((computed_subtotal - computed_discount) * invoice['tax_rate'] / 100)
    computed_total = round_money(computed_subtotal - computed_discount + computed_tax + invoice.get('shipping', 0))

    discrepancies = []
    computed_values = {'subtotal': computed_subtotal, 'discount': computed_discount, 'tax': computed_tax, 'total': computed_total}
    stated_values = {'subtotal': invoice['stated_subtotal'], 'discount': invoice['stated_discount'], 'tax': invoice['stated_tax'], 'total': invoice['stated_total']}

    for field in ['subtotal', 'discount', 'tax', 'total']:
        if computed_values[field] != stated_values[field]:
            discrepancies.append({'field': field, 'stated': stated_values[field], 'computed': computed_values[field], 'delta': round_money(computed_values[field] - stated_values[field])})

    return {'invoice_id': invoice['invoice_id'], 'vendor': invoice['vendor'], 'computed': computed_values, 'discrepancies': discrepancies, 'valid': len(discrepancies) == 0}

with open('sample_inputs/invoice_010.json') as f:
    invoice = json.load(f)

result = validate_invoice(invoice)

with open('output.json', 'w') as f:
    json.dump(result, f, indent=2)

print(json.dumps(result, indent=2))
